def search(query, df, bm25, model, index, top_k=10):
    query_vec = model.encode([query])
    distances, top_idx = index.search(query_vec.astype("float32"), 200)

    bm25_scores = bm25.get_scores(query.lower().split())

    vec_results = list(zip(top_idx[0], 1.0 / (1.0 + distances[0])))
    bm25_results = sorted(enumerate(bm25_scores), key=lambda x: x[1], reverse=True)[:200]

    ranks = {}
    for i, (idx, score) in enumerate(vec_results):
        ranks[idx] = ranks.get(idx, 0) + 1.0 / (i + 1.0 + 60.0)
    for i, (idx, score) in enumerate(bm25_results):
        if score > 0:
            ranks[idx] = ranks.get(idx, 0) + 1.0 / (i + 1.0 + 60.0)

    top_indices = sorted(ranks.items(), key=lambda x: x[1], reverse=True)[:top_k]
    res_idx = [i[0] for i in top_indices]

    return df.iloc[res_idx][["title", "overview"]].to_dict("records")

