def search(query, df, bm25, model, index, top_k=10):
    query_vec = model.encode([query]).astype("float32")
    _, idxs = index.search(query_vec, 100)
    idxs = idxs[0]

    candidates = df.iloc[idxs].copy()

    # Calculate genre overlap for the top 100
    query_genres = [g.lower() for g in query.split() if g.lower() in ["action", "comedy", "drama", "thriller", "horror", "romance", "sci-fi"]]

    if query_genres:
        def score_genre(g_str):
            return sum(1 for g in query_genres if g in g_str.lower())
        candidates['genre_boost'] = candidates['genres'].apply(score_genre)
    else:
        candidates['genre_boost'] = 0

    candidates['score'] = (candidates['genre_boost'] * 0.1)
    return candidates.sort_values(by="score", ascending=False).head(top_k)[["title", "overview"]].to_dict("records")

