def search(query, df, bm25, model, index, top_k=10):
    query_vec = model.encode([query])
    distances, indices = index.search(query_vec.astype("float32"), top_k * 5)

    candidates = df.iloc[indices[0]].copy()

    query_words = set(query.lower().split())
    def score_overlap(title):
        title_words = set(title.lower().split())
        return len(query_words.intersection(title_words))

    candidates['overlap'] = candidates['title'].apply(score_overlap)
    candidates['score'] = (1.0 / (distances[0] + 1e-6)) + (candidates['overlap'] * 2.0)

    ranked = candidates.sort_values(by="score", ascending=False)
    return ranked.head(top_k)[["title", "overview"]].to_dict("records")

