def search(query, df, bm25, model, index, top_k=10):
    query_vec = model.encode([query]).astype("float32")
    _, faiss_idxs = index.search(query_vec, 100)
    bm25_scores = bm25.get_scores(query.lower().split())

    top_faiss_idxs = faiss_idxs[0]
    candidate_scores = {}

    for i, idx in enumerate(top_faiss_idxs):
        candidate_scores[idx] = (1.0 / (i + 1))

    bm25_top = np.argsort(bm25_scores)[-100:]
    for i, idx in enumerate(bm25_top):
        candidate_scores[idx] = candidate_scores.get(idx, 0) + (1.0 / (100 - i + 50))

    final_idxs = sorted(candidate_scores, key=candidate_scores.get, reverse=True)[:top_k]
    return df.iloc[final_idxs].to_dict("records")

