def search(query, df, bm25, model, index, top_k=10):
    # Retrieve from FAISS
    query_vec = model.encode([query]).astype("float32")
    dists, idxs = index.search(query_vec, 200)
    faiss_scores = {idx: 1.0 / (1.0 + dist) for dist, idx in zip(dists[0], idxs[0]) if idx != -1}

    # Retrieve from BM25
    bm25_scores_raw = bm25.get_scores(query.lower().split())

    # Compute RRF
    rrf_scores = {}
    # Combine unique candidates
    all_indices = set(faiss_scores.keys()) | set(np.argsort(bm25_scores_raw)[-200:])

    # Get ranks
    faiss_sorted = sorted(faiss_scores.items(), key=lambda x: x[1], reverse=True)
    bm25_sorted = sorted([(i, bm25_scores_raw[i]) for i in all_indices], key=lambda x: x[1], reverse=True)

    faiss_ranks = {idx: r for r, (idx, _) in enumerate(faiss_sorted)}
    bm25_ranks = {idx: r for r, (idx, _) in enumerate(bm25_sorted)}

    for idx in all_indices:
        score = 0.0
        if idx in faiss_ranks:
            score += 1.0 / (60.0 + faiss_ranks[idx])
        if idx in bm25_ranks:
            score += 1.0 / (60.0 + bm25_ranks[idx])
        rrf_scores[idx] = score

    results = sorted(rrf_scores.items(), key=lambda x: x[1], reverse=True)[:top_k]
    result_df = df.iloc[[r[0] for r in results]].copy()

    return result_df.to_dict("records")

